@@ -0,0 +1,89 @@
+locals {
+  budget_managed_workspaces = var.workspaces
+
+  budget_framework_tags = [
+    {
+      key   = "databricks_partner"
+      value = "Abacus Insights"
+    },
+    {
+      key   = "databricks_partner_end_customer"
+      value = var.databricks_partner_end_customer
+    },
+    {
+      key   = "databricks_partner_end_customer_id"
+      value = var.databricks_partner_end_customer_id
+    }
+  ]
+}
+
+resource "databricks_budget" "workspace" {
+  for_each = local.budget_managed_workspaces
+
+  display_name = format(
+    "%s-%s-monthly-budget-usd",
+    local.label,
+    each.value,
+  )
+
+  alert_configurations {
+    time_period        = var.budget_time_period
+    trigger_type       = "CUMULATIVE_SPENDING_EXCEEDED"
+    quantity_type      = "LIST_PRICE_DOLLARS_USD"
+    quantity_threshold = tostring(var.budget_monthly_threshold_usd)
+
+    action_configurations {
+      action_type = "EMAIL_NOTIFICATION"
+      target      = var.budget_alert_email
+    }
+  }
+
+  filter {
+    workspace_id {
+      operator = "IN"
+      values = [
+        tostring(data.terraform_remote_state.databricks_provision.outputs.workspace_ids[each.value])
+      ]
+    }
+
+    tags {
+      key = "databricks_partner"
+      value {
+        operator = "IN"
+        values   = ["Abacus Insights"]
+      }
+    }
+
+    tags {
+      key = "databricks_partner_end_customer"
+      value {
+        operator = "IN"
+        values   = [var.databricks_partner_end_customer]
+      }
+    }
+
+    tags {
+      key = "databricks_partner_end_customer_id"
+      value {
+        operator = "IN"
+        values   = [var.databricks_partner_end_customer_id]
+      }
+    }
+  }
+}
+
+# Single account-level serverless budget policy for the tenant (all workspace IDs).
+resource "databricks_budget_policy" "serverless" {
+  count = length(local.budget_managed_workspaces) > 0 ? 1 : 0
+
+  policy_name = "${local.label}-serverless-budget-policy"
+
+  custom_tags = local.budget_framework_tags
+
+  binding_workspace_ids = [
+    for ws in sort(tolist(local.budget_managed_workspaces)) :
+    data.terraform_remote_state.databricks_provision.outputs.workspace_ids[ws]
+  ]
+
+  depends_on = [databricks_budget.workspace]
+}

